transform_js:
var categories = [];
var scatterData = [];
var errorBarData = [];
var diamondData = [];
var isTotal = [];

rawData.rows.forEach(function(r, i) {
  categories.push(r.study);
  isTotal.push(!!r.is_total);
  if (r.is_total) {
    diamondData.push({ value: [r.or, i, r.lo, r.hi], name: r.study });
  } else {
    scatterData.push({ value: [r.or, i], symbolSize: Math.max(10, r.weight * 0.6), name: r.study });
    errorBarData.push({ value: [r.lo, r.hi, i] });
  }
});

transformedData = {
  categories: categories,
  scatterData: scatterData,
  errorBarData: errorBarData,
  diamondData: diamondData,
  isTotal: isTotal
};

echarts_js:
option = {
  title: {
    text: 'メタ分析: オッズ比のフォレストプロット',
    left: 'center',
    top: 15,
    textStyle: { color: '#333' }
  },
  tooltip: {
    trigger: 'item',
    formatter: function(params) {
      if (params.seriesName === 'Effect Size') {
        var idx = Math.round(params.value[1]);
        var r = transformedData.errorBarData[idx];
        if (!r) return '';
        var lo = r.value[0];
        var hi = r.value[1];
        var val = params.value[0];
        return params.name + '<br/>OR: ' + val.toFixed(2) + ' [' + lo.toFixed(2) + ', ' + hi.toFixed(2) + ']';
      } else if (params.seriesName === 'Overall Effect') {
        var v = params.value;
        return params.name + '<br/>OR: ' + v[0].toFixed(2) + ' [' + v[2].toFixed(2) + ', ' + v[3].toFixed(2) + ']';
      }
      return '';
    }
  },
  grid: { left: 'center', width: 500, top: 80, bottom: 80, containLabel: true },
  xAxis: {
    type: 'log',
    min: 0.1,
    max: 10,
    axisLabel: { formatter: function(v){ return v; } },
    splitLine: { show: false },
    axisLine: { show: true },
    axisTick: { show: true },
    name: '< Favours Intervention       Favours Control >',
    nameLocation: 'middle',
    nameGap: 35,
    nameTextStyle: { fontWeight: 'bold' }
  },
  yAxis: {
    type: 'category',
    data: transformedData.categories,
    inverse: true,
    axisLine: { show: false },
    axisTick: { show: false },
    axisLabel: {
      margin: 15,
      fontSize: 13,
      formatter: function(value, index) {
        if (transformedData.isTotal[index]) {
          return '{bold|' + value + '}';
        }
        return value;
      },
      rich: {
        bold: { fontWeight: 'bold', fontSize: 13 }
      }
    }
  },
  series: [
    {
      name: 'Effect Size',
      type: 'scatter',
      data: transformedData.scatterData,
      itemStyle: { color: '#2b821d' },
      symbol: 'square',
      z: 3,
      markLine: {
        symbol: 'none',
        lineStyle: { color: '#888', width: 1.5, type: 'dashed' },
        label: { show: true, position: 'start', formatter: 'Null Effect', color: '#666' },
        data: [{ xAxis: 1 }]
      }
    },
    {
      name: '95% CI',
      type: 'custom',
      renderItem: function(params, api) {
        if (!transformedData.errorBarData[params.dataIndex]) return;
        var low = api.coord([api.value(0), api.value(2)]);
        var high = api.coord([api.value(1), api.value(2)]);
        return {
          type: 'line',
          shape: { x1: low[0], y1: low[1], x2: high[0], y2: high[1] },
          style: { stroke: '#2b821d', lineWidth: 1.5 }
        };
      },
      data: transformedData.errorBarData,
      z: 2
    },
    {
      name: 'Overall Effect',
      type: 'custom',
      renderItem: function(params, api) {
        var or = api.coord([api.value(0), api.value(1)]);
        var lo = api.coord([api.value(2), api.value(1)]);
        var hi = api.coord([api.value(3), api.value(1)]);

        // The true confidence interval width in pixels
        var ciWidthPix = hi[0] - lo[0];
        // Create a maximum size for the diamond symbol so it doesn't get huge
        // Cap the width at 24 pixels, or use the CI width if it's smaller
        var symbolWidth = Math.min(24, ciWidthPix);

        // Calculate square coordinates based on the center (or)
        var leftX = or[0] - (symbolWidth / 2);
        var rightX = or[0] + (symbolWidth / 2);
        var ht = symbolWidth / 2;

        return {
          // The sized-down square/diamond in the center
          type: 'polygon',
          shape: {
            points: [
              [leftX, or[1]],
              [or[0], or[1] - ht],
              [rightX, or[1]],
              [or[0], or[1] + ht]
            ]
          },
          style: { fill: '#c23531' }
        };
      },
      data: transformedData.diamondData,
      z: 4
    }
  ]
};
